// ── Données des articles ─────────────────────────────────────────────────────

const _articleData = {
    1: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Th\u00e9orie</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le MEDAF \u2014 Comprendre le prix du risque</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 6 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Lorsqu'on investit, on prend un risque. Il est donc naturel d'attendre une r\u00e9compense en \u00e9change. Mais combien exactement ? C'est pr\u00e9cis\u00e9ment la question \u00e0 laquelle r\u00e9pond le <strong style=\"color:var(--ink)\">Mod\u00e8le d'\u00c9valuation Des Actifs Financiers</strong> \u2014 le MEDAF, ou CAPM en anglais.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'id\u00e9e fondamentale</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le MEDAF, d\u00e9velopp\u00e9 dans les ann\u00e9es 1960 par William Sharpe (prix Nobel 1990), part d'une intuition simple : un investisseur rationnel ne prend pas de risque pour rien. Plus un actif est risqu\u00e9, plus il doit offrir un rendement \u00e9lev\u00e9 pour attirer des capitaux.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Mais tous les risques ne se valent pas. Certains peuvent \u00eatre \u00e9limin\u00e9s en diversifiant son portefeuille \u2014 c'est le <em>risque sp\u00e9cifique</em>. D'autres non : ils collent \u00e0 l'ensemble du march\u00e9 \u2014 c'est le <em>risque syst\u00e9matique</em>. Le march\u00e9 ne r\u00e9mun\u00e8re que ce second type de risque.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:24px;margin:28px 0\">\n<div style=\"font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted);margin-bottom:16px\">Illustration \u2014 La diversification r\u00e9duit le risque</div>\n<svg viewBox=\"0 0 600 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:100%;height:auto\">\n<defs><linearGradient id=\"gBlu2\" x1=\"0\" y1=\"0\" x2=\"1\" y2=\"0\"><stop offset=\"0%\" stop-color=\"#3466a0\" stop-opacity=\"0.15\"/><stop offset=\"100%\" stop-color=\"#3466a0\" stop-opacity=\"0.03\"/></linearGradient></defs>\n<line x1=\"60\" y1=\"20\" x2=\"60\" y2=\"170\" stroke=\"var(--border2)\" stroke-width=\"1.5\"/>\n<line x1=\"60\" y1=\"170\" x2=\"580\" y2=\"170\" stroke=\"var(--border2)\" stroke-width=\"1.5\"/>\n<text x=\"30\" y=\"100\" fill=\"var(--muted)\" font-size=\"10\" text-anchor=\"middle\" transform=\"rotate(-90,30,100)\" font-family=\"DM Sans,sans-serif\">Risque total</text>\n<text x=\"320\" y=\"192\" fill=\"var(--muted)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\">Nombre d'actifs</text>\n<path d=\"M70,40 Q120,42 180,70 Q260,100 360,130 Q440,148 560,155\" fill=\"none\" stroke=\"#1e3a5f\" stroke-width=\"2.5\" stroke-linecap=\"round\"/>\n<path d=\"M70,40 Q120,42 180,70 Q260,100 360,130 Q440,148 560,155 L560,155 L70,155 Z\" fill=\"url(#gBlu2)\"/>\n<line x1=\"70\" y1=\"155\" x2=\"560\" y2=\"155\" stroke=\"#c4820a\" stroke-width=\"1.8\" stroke-dasharray=\"6,4\"/>\n<text x=\"390\" y=\"90\" fill=\"#1e3a5f\" font-size=\"10\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Risque sp\u00e9cifique (diversifiable)</text>\n<text x=\"390\" y=\"163\" fill=\"#c4820a\" font-size=\"10\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Risque syst\u00e9matique</text>\n</svg>\n<p style=\"font-size:0.72rem;color:var(--muted);margin-top:10px;font-style:italic\">Plus on ajoute d'actifs non corr\u00e9l\u00e9s, plus le risque sp\u00e9cifique diminue. Il reste toujours un plancher : le risque de march\u00e9.</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La formule du MEDAF</h2>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">E(R<sub>i</sub>) = R<sub>f</sub> + \u03b2<sub>i</sub> \u00d7 (E(R<sub>m</sub>) \u2212 R<sub>f</sub>)</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\"><strong>R<sub>f</sub></strong> taux sans risque \u00b7 <strong>\u03b2<sub>i</sub></strong> b\u00eata \u00b7 <strong>E(R<sub>m</sub>)\u2212R<sub>f</sub></strong> prime de risque de march\u00e9</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le rendement attendu d'un actif est la somme du taux sans risque et d'une prime proportionnelle \u00e0 son exposition au march\u00e9, mesur\u00e9e par le b\u00eata.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La droite de march\u00e9 des titres (SML)</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:24px;margin:20px 0\">\n<div style=\"font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted);margin-bottom:16px\">Security Market Line</div>\n<svg viewBox=\"0 0 600 240\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:100%;height:auto\">\n<line x1=\"60\" y1=\"20\" x2=\"60\" y2=\"200\" stroke=\"var(--border2)\" stroke-width=\"1.5\"/>\n<line x1=\"60\" y1=\"200\" x2=\"580\" y2=\"200\" stroke=\"var(--border2)\" stroke-width=\"1.5\"/>\n<text x=\"320\" y=\"220\" fill=\"var(--muted)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\">B\u00eata (\u03b2)</text>\n<line x1=\"60\" y1=\"175\" x2=\"560\" y2=\"40\" stroke=\"#1e3a5f\" stroke-width=\"2.5\"/>\n<circle cx=\"60\" cy=\"175\" r=\"5\" fill=\"#7a1f2e\"/>\n<text x=\"70\" y=\"171\" fill=\"#7a1f2e\" font-size=\"10\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Rf</text>\n<line x1=\"310\" y1=\"200\" x2=\"310\" y2=\"107\" stroke=\"var(--border2)\" stroke-width=\"1\" stroke-dasharray=\"4,3\"/>\n<circle cx=\"310\" cy=\"107\" r=\"6\" fill=\"#c4820a\"/>\n<text x=\"318\" y=\"103\" fill=\"#c4820a\" font-size=\"10\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">March\u00e9 \u03b2=1</text>\n<circle cx=\"200\" cy=\"115\" r=\"6\" fill=\"#1a5c52\"/>\n<text x=\"210\" y=\"111\" fill=\"#1a5c52\" font-size=\"10\" font-family=\"DM Sans,sans-serif\">Sous-\u00e9valu\u00e9</text>\n<circle cx=\"400\" cy=\"115\" r=\"6\" fill=\"#b03045\"/>\n<text x=\"410\" y=\"111\" fill=\"#b03045\" font-size=\"10\" font-family=\"DM Sans,sans-serif\">Sur\u00e9valu\u00e9</text>\n<text x=\"60\" y=\"213\" fill=\"var(--muted2)\" font-size=\"9\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\">0</text>\n<text x=\"560\" y=\"213\" fill=\"var(--muted2)\" font-size=\"9\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\">2</text>\n</svg>\n<p style=\"font-size:0.72rem;color:var(--muted);margin-top:10px;font-style:italic\">Les actifs au-dessus de la SML sont sous-\u00e9valu\u00e9s (opportunit\u00e9 d'achat), ceux en dessous sont sur\u00e9valu\u00e9s.</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Limites et port\u00e9e</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Le MEDAF repose sur des hypoth\u00e8ses fortes : march\u00e9s parfaits, investisseurs rationnels, horizon unique, distributions normales. En pratique, ces conditions ne sont jamais pleinement r\u00e9unies.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Malgr\u00e9 ses limites, il reste le cadre de r\u00e9f\u00e9rence universel pour comprendre le lien risque-rendement et v\u00e9rifier si un portefeuille est correctement r\u00e9mun\u00e9r\u00e9 pour le risque pris.</p>",
    2: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Mesure du risque</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le B\u00eata (\u03b2) \u2014 Mesurer la sensibilit\u00e9 au march\u00e9</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Si le MEDAF est la th\u00e9orie, le <strong style=\"color:var(--ink)\">b\u00eata (\u03b2)</strong> en est l'outil de mesure central. Il quantifie la sensibilit\u00e9 d'un actif aux mouvements du march\u00e9. C'est la boussole du risque syst\u00e9matique.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Que signifie le b\u00eata ?</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Le b\u00eata mesure l'amplification ou l'att\u00e9nuation des mouvements de march\u00e9. Un b\u00eata de 1.5 signifie que si le march\u00e9 monte de 10 %, l'actif tend \u00e0 monter de 15 %.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Interpr\u00e9tation du b\u00eata</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Valeur</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Profil</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Exemple</th></tr>\n<tr style=\"border-bottom:1px solid var(--surface2)\"><td style=\"padding:10px 20px;font-family:var(--font-serif);font-weight:700;color:#7a1f2e\">\u03b2 &lt; 0</td><td style=\"padding:10px 20px;color:var(--ink2)\">Contre-cyclique</td><td style=\"padding:10px 20px;color:var(--muted)\">Or, d\u00e9riv\u00e9s de couverture</td></tr>\n<tr style=\"border-bottom:1px solid var(--surface2)\"><td style=\"padding:10px 20px;font-family:var(--font-serif);font-weight:700;color:#1a5c52\">\u03b2 = 0</td><td style=\"padding:10px 20px;color:var(--ink2)\">Ind\u00e9pendant</td><td style=\"padding:10px 20px;color:var(--muted)\">Bons du Tr\u00e9sor court terme</td></tr>\n<tr style=\"border-bottom:1px solid var(--surface2)\"><td style=\"padding:10px 20px;font-family:var(--font-serif);font-weight:700;color:#8a5a00\">0 &lt; \u03b2 &lt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">D\u00e9fensif</td><td style=\"padding:10px 20px;color:var(--muted)\">Utilities, sant\u00e9, alimentation</td></tr>\n<tr style=\"border-bottom:1px solid var(--surface2)\"><td style=\"padding:10px 20px;font-family:var(--font-serif);font-weight:700;color:#1e3a5f\">\u03b2 = 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">Neutre (march\u00e9)</td><td style=\"padding:10px 20px;color:var(--muted)\">ETF S&amp;P 500</td></tr>\n<tr><td style=\"padding:10px 20px;font-family:var(--font-serif);font-weight:700;color:#b03045\">\u03b2 &gt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">Agressif</td><td style=\"padding:10px 20px;color:var(--muted)\">Tech, biotech, cryptos</td></tr>\n</table>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le calcul du b\u00eata</h2>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">\u03b2<sub>i</sub> = Cov(R<sub>i</sub>, R<sub>m</sub>) / Var(R<sub>m</sub>)</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\"><strong>Cov</strong> : covariance actif/march\u00e9 \u00b7 <strong>Var</strong> : variance du march\u00e9</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">En pratique, on estime le b\u00eata visuellement par la <em>pente de la droite de r\u00e9gression</em> entre les rendements hebdomadaires de l'actif et ceux du march\u00e9.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:24px;margin:20px 0\">\n<div style=\"font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted);margin-bottom:16px\">Droite de r\u00e9gression \u2014 Estimation du b\u00eata</div>\n<svg viewBox=\"0 0 600 260\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:100%;height:auto\">\n<line x1=\"60\" y1=\"20\" x2=\"60\" y2=\"220\" stroke=\"var(--border2)\" stroke-width=\"1.5\"/>\n<line x1=\"60\" y1=\"220\" x2=\"580\" y2=\"220\" stroke=\"var(--border2)\" stroke-width=\"1.5\"/>\n<line x1=\"60\" y1=\"120\" x2=\"580\" y2=\"120\" stroke=\"var(--surface3)\" stroke-width=\"1\"/>\n<line x1=\"320\" y1=\"20\" x2=\"320\" y2=\"220\" stroke=\"var(--surface3)\" stroke-width=\"1\"/>\n<text x=\"30\" y=\"125\" fill=\"var(--muted)\" font-size=\"10\" text-anchor=\"middle\" transform=\"rotate(-90,30,125)\" font-family=\"DM Sans,sans-serif\">Rendement actif</text>\n<text x=\"320\" y=\"242\" fill=\"var(--muted)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\">Rendement march\u00e9</text>\n<circle cx=\"150\" cy=\"165\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"180\" cy=\"152\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"210\" cy=\"142\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"240\" cy=\"138\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"270\" cy=\"128\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"300\" cy=\"120\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"330\" cy=\"112\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"360\" cy=\"100\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"390\" cy=\"92\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"420\" cy=\"82\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"450\" cy=\"70\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"170\" cy=\"148\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"350\" cy=\"118\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<circle cx=\"130\" cy=\"178\" r=\"3.5\" fill=\"#3466a0\" opacity=\"0.6\"/>\n<line x1=\"100\" y1=\"185\" x2=\"520\" y2=\"55\" stroke=\"#1a5c52\" stroke-width=\"2.5\" stroke-linecap=\"round\"/>\n<text x=\"480\" y=\"62\" fill=\"#1a5c52\" font-size=\"11\" font-family=\"DM Sans,sans-serif\" font-weight=\"700\">\u03b2 = 1.5</text>\n<text x=\"54\" y=\"124\" fill=\"var(--muted2)\" font-size=\"9\" text-anchor=\"end\" font-family=\"DM Sans,sans-serif\">0%</text>\n<text x=\"316\" y=\"233\" fill=\"var(--muted2)\" font-size=\"9\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\">0%</text>\n</svg>\n<p style=\"font-size:0.72rem;color:var(--muted);margin-top:10px;font-style:italic\">La pente de la droite de r\u00e9gression donne le b\u00eata. Ici \u03b2 \u2248 1.5 : l'actif amplifie les mouvements du march\u00e9 d'un facteur 1.5.</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le b\u00eata du portefeuille</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">L'avantage du b\u00eata : il est <strong>additif</strong>. Le b\u00eata d'un portefeuille est simplement la moyenne pond\u00e9r\u00e9e des b\u00eatas de ses composants.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Un gestionnaire cherchant \u00e0 d\u00e9corr\u00e9ler son portefeuille du march\u00e9 visera un b\u00eata faible. \u00c0 l'inverse, un g\u00e9rant convaincu d'une hausse prochaine surpond\u00e8rera des actifs \u00e0 fort b\u00eata pour b\u00e9n\u00e9ficier d'un effet amplificateur naturel.</p>",
    3: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Th\u00e9orie avanc\u00e9e</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">L'APT \u2014 Quand le risque vient de partout</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 7 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le MEDAF est \u00e9l\u00e9gant mais simpliste : il r\u00e9duit tout le risque syst\u00e9matique \u00e0 un seul facteur \u2014 le march\u00e9. L'<strong style=\"color:var(--ink)\">Arbitrage Pricing Theory</strong> (APT), propos\u00e9e par Stephen Ross en 1976, l\u00e8ve cette contrainte et reconna\u00eet que l'\u00e9conomie est multidimensionnelle.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Plusieurs sources de risque</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Une action p\u00e9troli\u00e8re est sensible au prix du baril, aux taux d'int\u00e9r\u00eat, \u00e0 la croissance mondiale et aux tensions g\u00e9opolitiques. Pourquoi n'exposer qu'un seul chiffre pour capturer tout cela ? L'APT reconna\u00eet chaque source avec son propre b\u00eata et sa propre prime.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:24px;margin:28px 0\">\n<div style=\"font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted);margin-bottom:20px\">Les facteurs macro\u00e9conomiques de l'APT</div>\n<svg viewBox=\"0 0 600 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:100%;height:auto\">\n<rect x=\"245\" y=\"80\" width=\"110\" height=\"40\" rx=\"8\" fill=\"#1e3a5f\" opacity=\"0.9\"/>\n<text x=\"300\" y=\"105\" fill=\"white\" font-size=\"12\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Rendement actif</text>\n<rect x=\"30\" y=\"20\" width=\"100\" height=\"34\" rx=\"6\" fill=\"var(--surface2)\" stroke=\"var(--border)\"/>\n<text x=\"80\" y=\"41\" fill=\"var(--ink2)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Taux d'int\u00e9r\u00eat</text>\n<line x1=\"130\" y1=\"37\" x2=\"245\" y2=\"92\" stroke=\"#c4820a\" stroke-width=\"1.5\" stroke-dasharray=\"5,3\"/>\n<text x=\"185\" y=\"58\" fill=\"#c4820a\" font-size=\"9\" font-family=\"DM Sans,sans-serif\">\u03b2\u2081</text>\n<rect x=\"30\" y=\"83\" width=\"100\" height=\"34\" rx=\"6\" fill=\"var(--surface2)\" stroke=\"var(--border)\"/>\n<text x=\"80\" y=\"104\" fill=\"var(--ink2)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Inflation</text>\n<line x1=\"130\" y1=\"100\" x2=\"245\" y2=\"100\" stroke=\"#1a5c52\" stroke-width=\"1.5\" stroke-dasharray=\"5,3\"/>\n<text x=\"185\" y=\"96\" fill=\"#1a5c52\" font-size=\"9\" font-family=\"DM Sans,sans-serif\">\u03b2\u2082</text>\n<rect x=\"30\" y=\"146\" width=\"100\" height=\"34\" rx=\"6\" fill=\"var(--surface2)\" stroke=\"var(--border)\"/>\n<text x=\"80\" y=\"167\" fill=\"var(--ink2)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Croissance PIB</text>\n<line x1=\"130\" y1=\"163\" x2=\"245\" y2=\"108\" stroke=\"#7a1f2e\" stroke-width=\"1.5\" stroke-dasharray=\"5,3\"/>\n<text x=\"185\" y=\"148\" fill=\"#7a1f2e\" font-size=\"9\" font-family=\"DM Sans,sans-serif\">\u03b2\u2083</text>\n<rect x=\"470\" y=\"20\" width=\"100\" height=\"34\" rx=\"6\" fill=\"var(--surface2)\" stroke=\"var(--border)\"/>\n<text x=\"520\" y=\"41\" fill=\"var(--ink2)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Prix p\u00e9trole</text>\n<line x1=\"470\" y1=\"37\" x2=\"355\" y2=\"92\" stroke=\"#8a5a00\" stroke-width=\"1.5\" stroke-dasharray=\"5,3\"/>\n<text x=\"415\" y=\"58\" fill=\"#8a5a00\" font-size=\"9\" font-family=\"DM Sans,sans-serif\">\u03b2\u2084</text>\n<rect x=\"470\" y=\"83\" width=\"100\" height=\"34\" rx=\"6\" fill=\"var(--surface2)\" stroke=\"var(--border)\"/>\n<text x=\"520\" y=\"104\" fill=\"var(--ink2)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">March\u00e9 (CAPM)</text>\n<line x1=\"470\" y1=\"100\" x2=\"355\" y2=\"100\" stroke=\"#3466a0\" stroke-width=\"1.5\" stroke-dasharray=\"5,3\"/>\n<text x=\"415\" y=\"96\" fill=\"#3466a0\" font-size=\"9\" font-family=\"DM Sans,sans-serif\">\u03b2\u2085</text>\n<rect x=\"470\" y=\"146\" width=\"100\" height=\"34\" rx=\"6\" fill=\"var(--surface2)\" stroke=\"var(--border)\"/>\n<text x=\"520\" y=\"167\" fill=\"var(--ink2)\" font-size=\"10\" text-anchor=\"middle\" font-family=\"DM Sans,sans-serif\" font-weight=\"600\">Spread cr\u00e9dit</text>\n<line x1=\"470\" y1=\"163\" x2=\"355\" y2=\"108\" stroke=\"#1e3a5f\" stroke-width=\"1.5\" stroke-dasharray=\"5,3\"/>\n<text x=\"415\" y=\"148\" fill=\"#1e3a5f\" font-size=\"9\" font-family=\"DM Sans,sans-serif\">\u03b2\u2086</text>\n</svg>\n<p style=\"font-size:0.72rem;color:var(--muted);margin-top:12px;font-style:italic\">Chaque facteur macro\u00e9conomique contribue au rendement via son propre b\u00eata. L'APT est un MEDAF g\u00e9n\u00e9ralis\u00e9.</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'argument d'arbitrage</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Si deux actifs ont les m\u00eames expositions aux facteurs, ils doivent avoir le m\u00eame rendement attendu. Sinon, un arbitrage sans risque serait possible \u2014 ce qui, sur un march\u00e9 efficace, ne peut pas durer.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Cette logique est plus g\u00e9n\u00e9rale que celle du MEDAF : elle ne n\u00e9cessite pas que les investisseurs soient mean-variance optimaux, ni que les rendements soient normalement distribu\u00e9s.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">APT vs MEDAF</h2>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0\">\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:20px\">\n<div style=\"font-family:var(--font-serif);font-weight:700;color:var(--blue);font-size:1rem;margin-bottom:12px\">MEDAF</div>\n<ul style=\"list-style:none;padding:0;margin:0;font-size:0.85rem;color:var(--ink2);line-height:1.9\">\n<li style=\"padding:4px 0;border-bottom:1px solid var(--surface2)\">\u2726 1 seul facteur (march\u00e9)</li>\n<li style=\"padding:4px 0;border-bottom:1px solid var(--surface2)\">\u2726 Mod\u00e8le d'\u00e9quilibre g\u00e9n\u00e9ral</li>\n<li style=\"padding:4px 0;border-bottom:1px solid var(--surface2)\">\u2726 Simple et universel</li>\n<li style=\"padding:4px 0\">\u2726 Hypoth\u00e8ses fortes</li>\n</ul>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:20px\">\n<div style=\"font-family:var(--font-serif);font-weight:700;color:var(--teal);font-size:1rem;margin-bottom:12px\">APT</div>\n<ul style=\"list-style:none;padding:0;margin:0;font-size:0.85rem;color:var(--ink2);line-height:1.9\">\n<li style=\"padding:4px 0;border-bottom:1px solid var(--surface2)\">\u2726 K facteurs au choix</li>\n<li style=\"padding:4px 0;border-bottom:1px solid var(--surface2)\">\u2726 Argument d'arbitrage</li>\n<li style=\"padding:4px 0;border-bottom:1px solid var(--surface2)\">\u2726 Plus flexible et riche</li>\n<li style=\"padding:4px 0\">\u2726 Facteurs \u00e0 identifier</li>\n</ul>\n</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'APT dans la pratique</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">L'h\u00e9ritage direct de l'APT, c'est le mod\u00e8le de Fama-French (1993) : trois facteurs \u2014 le march\u00e9, la taille des entreprises (SMB) et leur valorisation (HML). Aujourd'hui, les mod\u00e8les \u00e0 5 ou 6 facteurs sont la norme en finance quantitative.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Les grands fonds institutionnels utilisent des mod\u00e8les APT calibr\u00e9s sur des dizaines de facteurs pour d\u00e9composer leur risque et construire des portefeuilles r\u00e9ellement diversifi\u00e9s \u2014 au sens factoriel du terme.</p>"
  };


// ── Articles supplémentaires (KPI de l'onglet actif) ─────────────────────────
Object.assign(_articleData, {
  4: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le P/E \u2014 Ce que vous payez vraiment pour chaque euro de profit</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Imaginez deux boulangeries \u00e0 vendre. La premi\u00e8re rapporte 10 000 \u20ac par an et se vend 100 000 \u20ac. La seconde rapporte le m\u00eame b\u00e9n\u00e9fice mais se vend 350 000 \u20ac. Laquelle est la plus ch\u00e8re ? La r\u00e9ponse semble \u00e9vidente \u2014 et pourtant, c'est exactement ce que mesure le ratio P/E en bourse. Cet indicateur, l'un des plus suivis au monde, vous dit combien le march\u00e9 est pr\u00eat \u00e0 payer pour chaque euro de b\u00e9n\u00e9fice g\u00e9n\u00e9r\u00e9 par une entreprise.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La formule</h2>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">P/E = Prix de l'action \u00f7 B\u00e9n\u00e9fice Net par Action (BNA)</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : action \u00e0 50 \u20ac \u00b7 BNA de 2,50 \u20ac \u2192 P/E = 20x</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le r\u00e9sultat s'exprime en \"fois\" (ou \"x\"). Un P/E de 20 signifie que le march\u00e9 paie 20 \u20ac pour chaque euro de b\u00e9n\u00e9fice annuel. C'est aussi l'inverse du rendement implicite : un P/E de 20 \u00e9quivaut \u00e0 un rendement b\u00e9n\u00e9ficiaire de 5 %.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Spectre des valorisations par secteur</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:24px;margin:28px 0\">\n<div style=\"font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted);margin-bottom:16px\">P/E moyen par secteur</div>\n<svg viewBox=\"0 0 600 220\" xmlns=\"http://www.w3.org/2000/svg\" style=\"width:100%;height:auto\">\n<text x=\"10\" y=\"38\" font-size=\"11\" fill=\"var(--muted)\" font-family=\"sans-serif\">Value / Banques</text>\n<text x=\"10\" y=\"78\" font-size=\"11\" fill=\"var(--muted)\" font-family=\"sans-serif\">Utilities</text>\n<text x=\"10\" y=\"118\" font-size=\"11\" fill=\"var(--muted)\" font-family=\"sans-serif\">Consommation</text>\n<text x=\"10\" y=\"158\" font-size=\"11\" fill=\"var(--muted)\" font-family=\"sans-serif\">Sant\u00e9</text>\n<text x=\"10\" y=\"198\" font-size=\"11\" fill=\"var(--muted)\" font-family=\"sans-serif\">Technologie</text>\n<rect x=\"160\" y=\"20\" width=\"66\" height=\"22\" rx=\"4\" fill=\"var(--teal)\" opacity=\"0.85\"/><text x=\"232\" y=\"35\" font-size=\"11\" font-weight=\"700\" fill=\"var(--ink)\" font-family=\"sans-serif\">~10x</text>\n<rect x=\"160\" y=\"60\" width=\"100\" height=\"22\" rx=\"4\" fill=\"var(--teal)\" opacity=\"0.7\"/><text x=\"266\" y=\"75\" font-size=\"11\" font-weight=\"700\" fill=\"var(--ink)\" font-family=\"sans-serif\">~15x</text>\n<rect x=\"160\" y=\"100\" width=\"146\" height=\"22\" rx=\"4\" fill=\"var(--blue)\" opacity=\"0.7\"/><text x=\"312\" y=\"115\" font-size=\"11\" font-weight=\"700\" fill=\"var(--ink)\" font-family=\"sans-serif\">~22x</text>\n<rect x=\"160\" y=\"140\" width=\"186\" height=\"22\" rx=\"4\" fill=\"var(--blue)\" opacity=\"0.85\"/><text x=\"352\" y=\"155\" font-size=\"11\" font-weight=\"700\" fill=\"var(--ink)\" font-family=\"sans-serif\">~28x</text>\n<rect x=\"160\" y=\"180\" width=\"234\" height=\"22\" rx=\"4\" fill=\"var(--amber)\" opacity=\"0.85\"/><text x=\"400\" y=\"195\" font-size=\"11\" font-weight=\"700\" fill=\"var(--ink)\" font-family=\"sans-serif\">~35x</text>\n<line x1=\"160\" y1=\"210\" x2=\"560\" y2=\"210\" stroke=\"var(--border)\" stroke-width=\"1\"/>\n<text x=\"160\" y=\"220\" font-size=\"9\" fill=\"var(--muted)\" font-family=\"sans-serif\" text-anchor=\"middle\">0</text>\n<text x=\"294\" y=\"220\" font-size=\"9\" fill=\"var(--muted)\" font-family=\"sans-serif\" text-anchor=\"middle\">20</text>\n<text x=\"427\" y=\"220\" font-size=\"9\" fill=\"var(--muted)\" font-family=\"sans-serif\" text-anchor=\"middle\">40</text>\n<text x=\"560\" y=\"220\" font-size=\"9\" fill=\"var(--muted)\" font-family=\"sans-serif\" text-anchor=\"middle\">60</text>\n</svg>\n<p style=\"font-size:0.72rem;color:var(--muted);margin-top:10px;font-style:italic\">Moyennes historiques indicatives. Les P/E varient selon les cycles \u00e9conomiques et les taux d'int\u00e9r\u00eat.</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Grille d'interpr\u00e9tation</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Interpr\u00e9tation du P/E</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">P/E</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Signal</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Profil typique</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 10</td><td style=\"padding:10px 20px;color:var(--ink2)\">Potentiel value</td><td style=\"padding:10px 20px;color:var(--ink2)\">Cyclique en bas de cycle ou difficult\u00e9 structurelle</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--ink);font-weight:700\">10 \u2013 20</td><td style=\"padding:10px 20px;color:var(--ink2)\">Zone raisonnable</td><td style=\"padding:10px 20px;color:var(--ink2)\">Valorisation mod\u00e9r\u00e9e, secteurs matures ou d\u00e9fensifs</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--blue);font-weight:700\">20 \u2013 35</td><td style=\"padding:10px 20px;color:var(--ink2)\">Croissance anticip\u00e9e</td><td style=\"padding:10px 20px;color:var(--ink2)\">Le march\u00e9 price une croissance future solide</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">&gt; 35</td><td style=\"padding:10px 20px;color:var(--ink2)\">Forte prime</td><td style=\"padding:10px 20px;color:var(--ink2)\">Optimisme \u00e9lev\u00e9 \u2014 moindre marge d'erreur</td></tr>\n</table>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Limites \u00e0 conna\u00eetre</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\"><strong>BNA n\u00e9gatif</strong> : si une entreprise est d\u00e9ficitaire, le P/E n'est pas calculable. Se tourner alors vers P/S ou EV/EBITDA.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\"><strong>\u00c9l\u00e9ments exceptionnels</strong> : un b\u00e9n\u00e9fice gonfl\u00e9 par une cession ou r\u00e9duit par une d\u00e9pr\u00e9ciation fausse le ratio. Toujours regarder le b\u00e9n\u00e9fice r\u00e9current.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\"><strong>Sensibilit\u00e9 aux taux</strong> : quand les taux montent, les valorisations se compriment. Un P/E de 25 en environnement de taux \u00e0 0 % n'a pas la m\u00eame signification qu'\u00e0 5 %.</p>",
  5: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Price/Book \u2014 Ce que vaut vraiment l'entreprise si tout s'arr\u00eatait</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Supposez qu'une entreprise ferme ses portes aujourd'hui. Elle vend ses actifs, rembourse ses dettes. Ce qui reste appartient aux actionnaires : c'est la valeur comptable. Le ratio Price-to-Book (P/B) compare ce que le march\u00e9 paie \u00e0 cette valeur de liquidation th\u00e9orique.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La formule</h2>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">P/B = Prix de l'action \u00f7 (Actifs \u2212 Dettes) par action</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Aussi \u00e9crit : Capitalisation boursi\u00e8re \u00f7 Capitaux propres totaux</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Un P/B de 1 signifie que le march\u00e9 valorise l'entreprise exactement \u00e0 la valeur de ses actifs nets. Un P/B inf\u00e9rieur \u00e0 1 est th\u00e9oriquement intrigant : le march\u00e9 valorise l'entreprise moins cher que sa valeur de liquidation.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Grille d'interpr\u00e9tation du P/B</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">P/B</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Signal</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">D\u00e9cote sur actifs \u2014 opportunit\u00e9 ou signal de difficult\u00e9s</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;font-weight:700\">1 \u2013 2</td><td style=\"padding:10px 20px;color:var(--ink2)\">Raisonnable \u2014 typique banques, industries matures</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--blue);font-weight:700\">2 \u2013 5</td><td style=\"padding:10px 20px;color:var(--ink2)\">Prime de qualit\u00e9 \u2014 marque forte, avantage concurrentiel</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">&gt; 5</td><td style=\"padding:10px 20px;color:var(--ink2)\">Forte intangibilit\u00e9 \u2014 logiciels, brevets, marques non comptabilis\u00e9es</td></tr>\n</table>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Quand le P/B est-il vraiment utile ?</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Le P/B brille pour les secteurs o\u00f9 les actifs tangibles sont centraux : <strong>banques, assurances, fonci\u00e8res, industries lourdes</strong>. En revanche, il perd de sa pertinence pour les entreprises dont la valeur r\u00e9side dans l'immat\u00e9riel \u2014 logiciels, marques, r\u00e9seaux. Leur P/B sera structurellement \u00e9lev\u00e9, sans que ce soit anormal.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Il existe une relation logique entre P/B et ROE : une entreprise qui g\u00e9n\u00e8re 20 % de rentabilit\u00e9 sur ses fonds propres m\u00e9rite naturellement un P/B plus \u00e9lev\u00e9 qu'une entreprise \u00e0 5 %. Toujours croiser les deux.</p>",
  6: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Price/Sales \u2014 Valoriser m\u00eame sans profit</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Une startup qui cro\u00eet \u00e0 80 % par an mais perd de l'argent \u2014 comment la valoriser ? Le P/E est inutilisable. C'est ici qu'intervient le <strong>Price-to-Sales</strong>, qui ram\u00e8ne la valorisation au chiffre d'affaires. Il offre un terrain de comparaison universel, m\u00eame pour des entreprises sans profit.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">P/S = Capitalisation boursi\u00e8re \u00f7 Chiffre d'affaires annuel</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : cap. boursi\u00e8re de 500 M\u20ac \u00b7 CA de 100 M\u20ac \u2192 P/S = 5x</div>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Niveaux de P/S selon le profil</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">P/S</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Profil typique</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">Distribution, industrie lourde \u2014 marges faibles structurelles</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;font-weight:700\">1 \u2013 3</td><td style=\"padding:10px 20px;color:var(--ink2)\">Zone standard \u2014 entreprises matures avec marges raisonnables</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--blue);font-weight:700\">3 \u2013 10</td><td style=\"padding:10px 20px;color:var(--ink2)\">SaaS, tech, biotech avec croissance visible</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">&gt; 10</td><td style=\"padding:10px 20px;color:var(--ink2)\">Hypercroissance \u2014 tr\u00e8s sensible aux d\u00e9ceptions</td></tr>\n</table>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'astuce du P/E normalis\u00e9</h2>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.3rem;color:var(--ink)\">P/E normalis\u00e9 = P/S \u00f7 Marge nette cible</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : P/S de 8x \u00b7 marge nette cible de 20% \u2192 P/E implicite = 40x</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Cette approche permet de tester la coh\u00e9rence d'une valorisation. Si le P/E implicite est de 100x pour une marge cible de 8 %, la valorisation est difficile \u00e0 d\u00e9fendre. Le P/S doit toujours \u00eatre accompagn\u00e9 d'une analyse des marges.</p>",
  7: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Price/FCF \u2014 Mesurer la valeur avec le vrai cash</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le ratio Price/FCF est consid\u00e9r\u00e9 par de nombreux investisseurs professionnels comme le multiple de valorisation le plus honn\u00eate. L\u00e0 o\u00f9 le b\u00e9n\u00e9fice net peut \u00eatre fa\u00e7onn\u00e9 par des choix comptables, le free cash flow est du cash r\u00e9el \u2014 celui qui entre dans la caisse apr\u00e8s que l'entreprise a pay\u00e9 ses investissements.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">P/FCF = Capitalisation boursi\u00e8re / Free Cash Flow annuel</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">FCF = Flux op\u00e9rationnel \u2212 Capex (d\u00e9penses d'investissement)</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Pourquoi plus fiable que le P/E</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le b\u00e9n\u00e9fice net peut \u00eatre artificiellement gonfl\u00e9 par des choix d'amortissement, des provisions ou des cessions d'actifs. Le FCF est beaucoup plus difficile \u00e0 manipuler : soit l'argent est dans la caisse, soit il n'y est pas.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n<div style=\"font-size:0.72rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;color:var(--amber);margin-bottom:8px\">Exemple concret</div>\n<p style=\"font-size:0.92rem;line-height:1.65;color:var(--ink2);margin:0\">Entreprise avec un b\u00e9n\u00e9fice net de 100 M\u20ac mais des capex de maintenance de 80 M\u20ac. Son FCF r\u00e9el est de 20 M\u20ac. Si le march\u00e9 la valorise \u00e0 1 Md\u20ac, le P/E apparent est de 10\u00d7 (attractif) mais le P/FCF est de 50\u00d7 (tr\u00e8s cher).</p>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Rep\u00e8res P/FCF</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">P/FCF</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Signal</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 15</td><td style=\"padding:10px 20px;color:var(--ink2)\">Potentiellement attractif</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">15 \u2013 25</td><td style=\"padding:10px 20px;color:var(--ink2)\">Valorisation correcte</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&gt; 25</td><td style=\"padding:10px 20px;color:var(--ink2)\">Prime \u00e9lev\u00e9e \u2014 justifi\u00e9 uniquement par forte croissance</td></tr>\n</table>\n</div>",
  8: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le PEG Ratio \u2014 Le P/E ajust\u00e9 \u00e0 la croissance</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Un P/E de 30 est-il forc\u00e9ment plus cher qu'un P/E de 15 ? Pas n\u00e9cessairement. C'est l'intuition fondatrice du PEG Ratio, popularis\u00e9 par Peter Lynch. Le PEG int\u00e8gre la croissance des b\u00e9n\u00e9fices dans l'\u00e9quation de valorisation \u2014 et renverse parfois compl\u00e8tement le jugement.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">PEG = P/E \u00f7 Taux de croissance annuel des b\u00e9n\u00e9fices (%)</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : P/E de 30 \u00f7 croissance de 30 % = PEG de 1,0</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La r\u00e8gle empirique de Peter Lynch</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Peter Lynch utilisait une r\u00e8gle simple : <strong>une action est correctement valoris\u00e9e quand son PEG est \u00e9gal \u00e0 1</strong>. En dessous de 1, potentiellement sous-\u00e9valu\u00e9e. Au-dessus de 2, la croissance attendue est d\u00e9j\u00e0 largement int\u00e9gr\u00e9e dans le prix.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Rep\u00e8res PEG</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">PEG</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Signal</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">Potentiellement sous-\u00e9valu\u00e9 \u2014 croissance non enti\u00e8rement pric\u00e9e</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">1 \u2013 2</td><td style=\"padding:10px 20px;color:var(--ink2)\">Valorisation juste \u2014 coh\u00e9rente avec les perspectives</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&gt; 2</td><td style=\"padding:10px 20px;color:var(--ink2)\">Cher \u2014 croissance future d\u00e9j\u00e0 largement int\u00e9gr\u00e9e</td></tr>\n</table>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Le PEG n'est aussi bon que l'estimation de croissance qu'on y introduit. Utilisez de pr\u00e9f\u00e9rence la croissance historique sur 5 ans, pas les estimations prospectives souvent optimistes des analystes.</p>",
  9: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">EV/Revenue \u2014 La valeur d'entreprise face au chiffre d'affaires</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">L'EV/Revenue mesure combien l'ensemble des apporteurs de capitaux (actionnaires <em>et</em> cr\u00e9anciers) paient pour chaque euro de chiffre d'affaires. Contrairement au P/S, il prend en compte la structure financi\u00e8re de l'entreprise.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">EV = Capitalisation + Dette nette \u2212 Tr\u00e9sorerie</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">EV/Rev = (Capitalisation + Dettes nettes) / CA \u2014 ind\u00e9pendant de la structure du capital</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'avantage d\u00e9cisif sur le P/S</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Deux soci\u00e9t\u00e9s avec le m\u00eame CA et la m\u00eame capitalisation auront un P/S identique, m\u00eame si l'une porte 500 M\u20ac de dette nette et l'autre a 500 M\u20ac de tr\u00e9sorerie. L'EV/Revenue, lui, int\u00e8gre cette r\u00e9alit\u00e9.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Rep\u00e8res EV/Revenue</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">EV/Rev</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Contexte</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 2\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">Industrie, value \u2014 valorisation modeste</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">2\u00d7 \u2013 8\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">Tech \u00e9tablie, SaaS rentable</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&gt; 10\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">SaaS hypercroissance \u2014 justifi\u00e9 seulement par croissance &gt; 40 %</td></tr>\n</table>\n</div>",
  10: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Fondamentaux</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Capitalisation Boursi\u00e8re \u2014 Ce que le march\u00e9 pense de votre entreprise</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La <strong>capitalisation boursi\u00e8re</strong> est ce que l'ensemble des investisseurs accepte collectivement de payer pour poss\u00e9der 100 % de l'entreprise \u00e0 l'instant T. Ce n'est pas la valeur comptable, ni la valeur des actifs.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">Capitalisation = Prix de l'action \u00d7 Nombre d'actions en circulation</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : action \u00e0 150 \u20ac \u00d7 500 millions d'actions = capitalisation de 75 milliards \u20ac</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le spectre des tailles de march\u00e9</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<div style=\"padding:14px 20px;background:var(--surface2);font-size:0.65rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Cat\u00e9gories par capitalisation</div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Cat\u00e9gorie</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Seuil</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Profil</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--ink2)\">Nano/Micro cap</td><td style=\"padding:10px 20px;color:var(--ink2)\">&lt; 300 M\u20ac</td><td style=\"padding:10px 20px;color:var(--ink2)\">Forte volatilit\u00e9, liquidit\u00e9 faible, potentiel \u00e9lev\u00e9</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--ink2)\">Small cap</td><td style=\"padding:10px 20px;color:var(--ink2)\">300 M \u2013 2 Mrd</td><td style=\"padding:10px 20px;color:var(--ink2)\">PME innovantes, croissance visible</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--ink2)\">Mid cap</td><td style=\"padding:10px 20px;color:var(--ink2)\">2 \u2013 10 Mrd</td><td style=\"padding:10px 20px;color:var(--ink2)\">Leaders sectoriels, profil \u00e9quilibr\u00e9</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--ink2)\">Large cap</td><td style=\"padding:10px 20px;color:var(--ink2)\">10 \u2013 200 Mrd</td><td style=\"padding:10px 20px;color:var(--ink2)\">CAC 40, stabilit\u00e9, dividendes fr\u00e9quents</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--ink2)\">Mega cap</td><td style=\"padding:10px 20px;color:var(--ink2)\">&gt; 200 Mrd</td><td style=\"padding:10px 20px;color:var(--ink2)\">Apple, LVMH \u2014 liquidit\u00e9 maximale</td></tr>\n</table>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Capitalisation vs Valeur d'Entreprise</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">La capitalisation ignore la structure financi\u00e8re. La <strong>Valeur d'Entreprise (EV)</strong> = Capitalisation + Dette financi\u00e8re nette \u2212 Tr\u00e9sorerie est plus compl\u00e8te pour comparer des soci\u00e9t\u00e9s aux bilans diff\u00e9rents.</p>",
  11: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Rentabilit\u00e9</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le BNA \u2014 Le b\u00e9n\u00e9fice ramen\u00e9 \u00e0 l'\u00e9chelle de chaque action</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Une entreprise peut afficher 2 milliards de b\u00e9n\u00e9fice et \u00eatre jug\u00e9e d\u00e9cevante. Une autre peut publier 400 millions et faire bondir son cours. La cl\u00e9 : le nombre d'actions. Le <strong>B\u00e9n\u00e9fice Net par Action (BNA)</strong> neutralise cette variable pour comparer les r\u00e9sultats sur un pied d'\u00e9galit\u00e9.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">BNA = B\u00e9n\u00e9fice net / Nombre d'actions en circulation</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : 800 M\u20ac \u00f7 400 M actions = BNA de 2,00 \u20ac</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">BNA basique vs BNA dilu\u00e9</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le <strong>BNA dilu\u00e9</strong> tient compte de toutes les actions potentiellement cr\u00e9\u00e9es si les stock-options et obligations convertibles \u00e9taient exerc\u00e9es. Il est toujours inf\u00e9rieur ou \u00e9gal au BNA basique. Dans les entreprises tech \u00e0 forte culture de r\u00e9mun\u00e9ration en actions, la dilution peut d\u00e9passer 5 \u00e0 10 % par an.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:16px 22px;margin:20px 0\">\n<p style=\"font-size:0.88rem;line-height:1.7;color:var(--ink2);margin:0\"><strong>Exemple :</strong> 500 M\u20ac \u00b7 200 M actions (basique) \u2192 BNA = 2,50 \u20ac \u00b7 Avec 40 M options : BNA dilu\u00e9 = 500 \u00f7 240 = 2,08 \u20ac \u2014 \u00e9cart de 17 %.</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La croissance du BNA : moteur num\u00e9ro un des cours</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Sur le long terme, la croissance du BNA explique l'essentiel de la performance boursi\u00e8re. Quand une entreprise \"bat le consensus\" (BNA sup\u00e9rieur aux attentes), le cours r\u00e9agit positivement \u2014 m\u00eame si le BNA est en baisse absolue par rapport \u00e0 l'an pass\u00e9.</p>",
  12: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Flux de tr\u00e9sorerie</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Free Cash Flow \u2014 Le cash qui reste vraiment dans les mains de l'entreprise</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le b\u00e9n\u00e9fice net est une construction comptable. Le cash, lui, est r\u00e9el. Une entreprise peut afficher des b\u00e9n\u00e9fices en croissance pendant des ann\u00e9es tout en \u00e9tant perp\u00e9tuellement \u00e0 court de liquidit\u00e9s. C'est pour trancher cette ambigu\u00eft\u00e9 que les professionnels utilisent le <strong>Free Cash Flow</strong>.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">FCF = Flux de tr\u00e9sorerie op\u00e9rationnel \u2212 Capex</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Capex = d\u00e9penses d'investissement (machines, \u00e9quipements, immobilisations)</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Pourquoi les amortissements sont \"rajout\u00e9s\"</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Une machine achet\u00e9e 1 M\u20ac est amortie sur 10 ans : 100 k\u20ac de charge annuelle. Mais le cash a quitt\u00e9 l'entreprise lors de l'achat. L'amortissement est une charge <strong>non d\u00e9caiss\u00e9e</strong> \u2014 on la rajoute au r\u00e9sultat net pour retrouver le cash r\u00e9el.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le FCF : le nerf de la guerre</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Une fois le FCF calcul\u00e9, la direction peut l'allouer de quatre fa\u00e7ons :</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:20px 0\">\n<div style=\"background:var(--surface2);border-radius:8px;padding:14px 16px\"><div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;color:var(--teal);margin-bottom:6px\">Dividendes</div><p style=\"font-size:0.82rem;line-height:1.6;color:var(--ink2);margin:0\">Redistribution directe aux actionnaires.</p></div>\n<div style=\"background:var(--surface2);border-radius:8px;padding:14px 16px\"><div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;color:var(--blue);margin-bottom:6px\">Rachats d'actions</div><p style=\"font-size:0.82rem;line-height:1.6;color:var(--ink2);margin:0\">R\u00e9duit les actions, augmente m\u00e9caniquement le BNA.</p></div>\n<div style=\"background:var(--surface2);border-radius:8px;padding:14px 16px\"><div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;color:var(--amber);margin-bottom:6px\">Remboursement dette</div><p style=\"font-size:0.82rem;line-height:1.6;color:var(--ink2);margin:0\">R\u00e9duit le levier et les charges d'int\u00e9r\u00eats.</p></div>\n<div style=\"background:var(--surface2);border-radius:8px;padding:14px 16px\"><div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.1em;text-transform:uppercase;color:var(--rose);margin-bottom:6px\">Acquisitions</div><p style=\"font-size:0.82rem;line-height:1.6;color:var(--ink2);margin:0\">La plus cr\u00e9atrice de valeur \u2014 si bien ex\u00e9cut\u00e9e.</p></div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\"><strong>FCF Yield</strong> = FCF / Capitalisation : si un titre affiche 8 % de FCF Yield vs un taux obligataire \u00e0 4 %, il g\u00e9n\u00e8re deux fois plus de \"rendement cash\" \u2014 avec plus de risque, certes.</p>",
  13: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Rentabilit\u00e9</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Marge Op\u00e9rationnelle \u2014 L'efficacit\u00e9 brute du c\u0153ur de m\u00e9tier</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La <strong>marge op\u00e9rationnelle</strong> mesure la capacit\u00e9 d'une entreprise \u00e0 d\u00e9gager un b\u00e9n\u00e9fice \u00e0 partir de son seul c\u0153ur de m\u00e9tier, avant de payer ses cr\u00e9anciers et l'\u00c9tat. C'est l'outil id\u00e9al pour comparer des entreprises ind\u00e9pendamment de leur niveau d'endettement.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">Marge op\u00e9rationnelle = EBIT / Chiffre d'affaires \u00d7 100</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">EBIT = Earnings Before Interest and Taxes (r\u00e9sultat avant int\u00e9r\u00eats et imp\u00f4ts)</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Benchmarks sectoriels</h2>\n<div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:20px 0 28px\">\n<div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Logiciel / SaaS</div>\n<div style=\"font-family:var(--font-serif);font-size:1.6rem;font-weight:700;color:var(--blue)\">25\u201340 %</div>\n<div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Co\u00fbts marginaux faibles, fort effet d'\u00e9chelle</div>\n</div>\n<div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Industrie</div>\n<div style=\"font-family:var(--font-serif);font-size:1.6rem;font-weight:700;color:var(--teal)\">8\u201315 %</div>\n<div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Co\u00fbts fixes \u00e9lev\u00e9s, investissements lourds</div>\n</div>\n<div style=\"background:var(--surface2);border-radius:8px;padding:16px 18px;border:1px solid var(--border)\">\n<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--muted);margin-bottom:8px\">Distribution</div>\n<div style=\"font-family:var(--font-serif);font-size:1.6rem;font-weight:700;color:var(--amber)\">2\u20135 %</div>\n<div style=\"font-size:0.75rem;color:var(--muted);margin-top:6px\">Volumes \u00e9normes, marges unitaires compress\u00e9es</div>\n</div>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--blue);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0\">\n<p style=\"font-size:0.9rem;line-height:1.65;color:var(--ink2);margin:0\"><strong>\u00c0 retenir :</strong> La marge op\u00e9rationnelle est neutre vis-\u00e0-vis de la structure financi\u00e8re. Deux entreprises identiques, l'une tr\u00e8s endett\u00e9e et l'autre sans dettes, afficheront la m\u00eame marge op\u00e9rationnelle si leur exploitation est aussi efficace.</p>\n</div>",
  14: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Rentabilit\u00e9</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Marge Nette \u2014 Ce qui reste vraiment pour les actionnaires</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">La <strong>marge nette</strong> r\u00e9v\u00e8le ce qui appartient r\u00e9ellement aux actionnaires une fois que l'entreprise a tout r\u00e9gl\u00e9 \u2014 fournisseurs, salari\u00e9s, banquiers et fisc. C'est le dernier centime du compte de r\u00e9sultat.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">Marge nette = B\u00e9n\u00e9fice net / Chiffre d'affaires \u00d7 100</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Apr\u00e8s int\u00e9r\u00eats sur la dette et imp\u00f4t sur les soci\u00e9t\u00e9s</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'\u00e9cart r\u00e9v\u00e9lateur entre marge op\u00e9rationnelle et marge nette</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Plus l'\u00e9cart entre ces deux marges est grand, plus l'entreprise porte un fardeau de dettes ou b\u00e9n\u00e9ficie d'un environnement fiscal particulier. Si la marge op\u00e9rationnelle est de 15 % et la marge nette de 9 %, les 6 points restants sont absorb\u00e9s par les int\u00e9r\u00eats et l'imp\u00f4t.</p>\n<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:16px;margin:20px 0\">\n<div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:10px\">Forte marge nette</div>\n<p style=\"font-size:0.88rem;line-height:1.7;color:var(--ink2)\"><strong>Logiciels / SaaS</strong> \u2014 15\u201330 %<br><strong>Luxe</strong> \u2014 10\u201325 %<br><strong>Pharmacie</strong> \u2014 15\u201325 %</p>\n</div>\n<div style=\"background:var(--surface2);border-radius:8px;padding:18px;border:1px solid var(--border)\">\n<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:10px\">Faible marge nette</div>\n<p style=\"font-size:0.88rem;line-height:1.7;color:var(--ink2)\"><strong>Grande distribution</strong> \u2014 1\u20133 %<br><strong>Transport a\u00e9rien</strong> \u2014 1\u20135 %<br><strong>Agroalimentaire</strong> \u2014 2\u20136 %</p>\n</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">La marge nette utilis\u00e9e seule peut induire en erreur : une faible marge nette peut venir d'une dette excessive, pas d'une mauvaise exploitation. Toujours la croiser avec la marge op\u00e9rationnelle.</p>",
  15: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Rentabilit\u00e9</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le ROE \u2014 Ce que l'entreprise rapporte sur chaque euro des actionnaires</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le <strong>ROE</strong> (Return On Equity) mesure le taux de rendement g\u00e9n\u00e9r\u00e9 par l'entreprise sur les capitaux appartenant aux actionnaires. C'est l'un des indicateurs favoris de Warren Buffett pour identifier les entreprises \u00e0 avantage concurrentiel durable.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">ROE = B\u00e9n\u00e9fice net / Capitaux propres \u00d7 100</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Un ROE de 20 % signifie que pour chaque euro des actionnaires, l'entreprise g\u00e9n\u00e8re 0,20 \u20ac de profit annuel</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La d\u00e9composition DuPont</h2>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.2rem;color:var(--ink);line-height:1.8\">ROE = <span style=\"color:var(--teal)\">Marge nette</span> \u00d7 <span style=\"color:var(--blue)\">Rotation des actifs</span> \u00d7 <span style=\"color:var(--rose)\">Levier financier</span></div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">(B\u00e9n\u00e9fice/CA) \u00d7 (CA/Actif total) \u00d7 (Actif total/Capitaux propres)</div>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Cette d\u00e9composition r\u00e9v\u00e8le l'<em>origine</em> du ROE : vient-il d'une forte rentabilit\u00e9 commerciale, d'une utilisation efficace des actifs, ou d'un levier financier \u00e9lev\u00e9 ? Trois sources tr\u00e8s diff\u00e9rentes de performance.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les limites : quand le ROE ment</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\"><strong>La dette</strong> \u2014 En s'endettant massivement, l'entreprise r\u00e9duit ses capitaux propres au d\u00e9nominateur. Le m\u00eame b\u00e9n\u00e9fice net donne un ROE plus \u00e9lev\u00e9 \u2014 mais c'est un ROE fragile.</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\"><strong>Les rachats d'actions</strong> \u2014 Ils r\u00e9duisent comptablement les capitaux propres. Apple, Microsoft ou Visa affichent des ROE spectaculaires (100 %+) gr\u00e2ce \u00e0 leurs rachats massifs. Toujours compl\u00e9ter avec le ROA (Return on Assets) qui neutralise l'effet de levier.</p>",
  16: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Dividendes</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Rendement du Dividende \u2014 Le taux d'int\u00e9r\u00eat naturel de l'action</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le <strong>rendement du dividende</strong> mesure le rapport entre le dividende annuel vers\u00e9 et le prix actuel de l'action. C'est le \"taux d'int\u00e9r\u00eat naturel\" de l'actif : plus le cours monte, plus le rendement baisse \u2014 et inversement.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">Rendement = (Dividende annuel / Prix de l'action) \u00d7 100</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Exemple : dividende de 2 \u20ac \u00b7 cours de 50 \u20ac \u2192 rendement de 4 %</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le pi\u00e8ge du rendement \u00e9lev\u00e9</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Un rendement de 10 % ou 15 % semble extraordinaire. Mais c'est souvent un signal d'alarme \u2014 le ph\u00e9nom\u00e8ne s'appelle le <strong>dividend yield trap</strong>. Le march\u00e9 a fait chuter le cours car il anticipe une r\u00e9duction du dividende. L'investisseur touche un ou deux versements g\u00e9n\u00e9reux, puis le dividende est coup\u00e9.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:16px 22px;margin:20px 0\">\n<div style=\"font-size:0.7rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--rose);margin-bottom:6px\">Signaux d'alerte</div>\n<ul style=\"font-size:0.88rem;line-height:1.8;color:var(--ink2);padding-left:18px\">\n<li>Rendement nettement sup\u00e9rieur \u00e0 la moyenne sectorielle</li>\n<li>Payout ratio sup\u00e9rieur \u00e0 80\u201390 %</li>\n<li>Endettement en hausse, flux de tr\u00e9sorerie en baisse</li>\n<li>Cours en chute de plus de 30 % sur 12 mois</li>\n</ul>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les Dividend Aristocrats</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Certaines entreprises augmentent leur dividende chaque ann\u00e9e depuis au moins 25 ans cons\u00e9cutifs. Ce club tr\u00e8s s\u00e9lect (Johnson &amp; Johnson, Procter &amp; Gamble, Coca-Cola) signale une solidit\u00e9 fondamentale exceptionnelle. Un rendement mod\u00e9r\u00e9 mais croissant vaut souvent mieux qu'un rendement \u00e9lev\u00e9 et fragile.</p>",
  17: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Dividendes</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Payout Ratio \u2014 Quelle part des b\u00e9n\u00e9fices part en dividendes ?</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le <strong>payout ratio</strong> mesure la part des b\u00e9n\u00e9fices redistribu\u00e9e aux actionnaires. Trop bas, l'entreprise th\u00e9saurise sans partager. Trop haut, elle distribue plus qu'elle ne peut se permettre. C'est une radiographie de la g\u00e9n\u00e9rosit\u00e9 <em>et</em> de la prudence d'une direction.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">Payout = (Dividende par action / BNA) \u00d7 100</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">FCF Payout = Dividendes vers\u00e9s / Free Cash Flow \u2014 plus fiable car bas\u00e9 sur du cash r\u00e9el</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les quatre zones</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"background:var(--surface2);border-bottom:1px solid var(--border)\"><th style=\"padding:10px 16px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Payout</th><th style=\"padding:10px 16px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Interpr\u00e9tation</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--teal);font-weight:700\">0 \u2013 40 %</td><td style=\"padding:10px 16px;color:var(--ink2)\">R\u00e9investissement prioritaire \u2014 dividende tr\u00e8s s\u00fbr avec marge de progression</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--blue);font-weight:700\">40 \u2013 70 %</td><td style=\"padding:10px 16px;color:var(--ink2)\">Zone id\u00e9ale \u2014 partage g\u00e9n\u00e9reux tout en conservant assez pour se d\u00e9velopper</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--amber);font-weight:700\">70 \u2013 100 %</td><td style=\"padding:10px 16px;color:var(--ink2)\">Vigilance \u2014 viable si r\u00e9sultats stables, peu de marge en cas de contraction</td></tr>\n<tr><td style=\"padding:10px 16px;color:var(--rose);font-weight:700\">&gt; 100 %</td><td style=\"padding:10px 16px;color:var(--ink2)\">Danger \u2014 l'entreprise finance son dividende par la dette ou ses r\u00e9serves</td></tr>\n</table>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--teal);border-radius:0 8px 8px 0;padding:16px 22px;margin:20px 0\">\n<p style=\"font-size:0.88rem;line-height:1.75;color:var(--ink2);margin:0\"><strong>Exception :</strong> Les REIT (fonci\u00e8res cot\u00e9es) sont l\u00e9galement tenues de distribuer plus de 90 % de leurs revenus. Un payout \u00e9lev\u00e9 y est structurel et normal \u2014 pas un signal d'alarme.</p>\n</div>",
  18: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Actions</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Les Actions en Circulation \u2014 Dilution, rachats et ce qu'ils r\u00e9v\u00e8lent</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le nombre d'actions en circulation \u00e9volue dans le temps : il augmente quand l'entreprise \u00e9met de nouvelles actions (dilution), il diminue quand elle rach\u00e8te ses propres titres (buybacks). Cette \u00e9volution est l'un des signaux les plus sous-estim\u00e9s en analyse boursi\u00e8re.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'impact sur le BNA</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">\u00c0 r\u00e9sultat constant, si le nombre d'actions diminue, le BNA augmente m\u00e9caniquement. Apple a rachet\u00e9 pour plus de 600 Mrd$ de ses propres actions depuis 2012, r\u00e9duisant son flottant de plus de 40 %. Ce programme a \u00e9t\u00e9 l'un des moteurs de la progression du BNA bien au-del\u00e0 de la seule croissance des ventes.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les rachats comme signal de confiance</h2>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:16px\">Quand une direction rach\u00e8te massivement ses propres actions, elle envoie un message implicite : <strong>\"nous pensons que notre action est sous-\u00e9valu\u00e9e\"</strong>. Personne ne conna\u00eet mieux l'entreprise que ses dirigeants.</p>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"background:var(--surface2);border-bottom:1px solid var(--border)\"><th style=\"padding:10px 16px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">\u00c9volution</th><th style=\"padding:10px 16px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Signal</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--ink2)\">Baisse r\u00e9guli\u00e8re (\u22122 \u00e0 \u22125 %/an)</td><td style=\"padding:10px 16px;color:var(--teal);font-weight:700\">Bullish \u2014 rachats actifs</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--ink2)\">Stabilit\u00e9 (\u00b11 %/an)</td><td style=\"padding:10px 16px;color:var(--muted);font-weight:700\">Neutre</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--ink2)\">Hausse mod\u00e9r\u00e9e (+1 \u00e0 +3 %/an)</td><td style=\"padding:10px 16px;color:var(--amber);font-weight:700\">Attention \u2014 stock-options exerc\u00e9es</td></tr>\n<tr><td style=\"padding:10px 16px;color:var(--ink2)\">Hausse forte (&gt;+5 %/an)</td><td style=\"padding:10px 16px;color:var(--rose);font-weight:700\">Bearish \u2014 augmentation de capital ou acquisition dilutive</td></tr>\n</table>\n</div>",
  19: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Sant\u00e9 financi\u00e8re</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Dette / Capitaux Propres \u2014 Mesurer l'\u00e9quilibre dettes / fonds propres</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le ratio <strong>D/E (Debt-to-Equity)</strong> mesure l'\u00e9quilibre entre les deux sources de financement d'une entreprise : la dette (ce qu'elle doit) et les capitaux propres (ce qu'elle poss\u00e8de en propre). C'est le premier indicateur \u00e0 consulter pour \u00e9valuer la solidit\u00e9 financi\u00e8re.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">D/E = Dettes totales / Capitaux propres</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Un D/E de 1,5 signifie que pour chaque euro appartenant aux actionnaires, l'entreprise doit 1,50 \u20ac \u00e0 ses cr\u00e9anciers</div>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"background:var(--surface2);border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">D/E</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Interpr\u00e9tation</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&lt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">Peu endett\u00e9 \u2014 solidit\u00e9 rassurante</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">1 \u2013 2</td><td style=\"padding:10px 20px;color:var(--ink2)\">Mod\u00e9r\u00e9 \u2014 levier raisonnable, courant dans l'industrie</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&gt; 2</td><td style=\"padding:10px 20px;color:var(--ink2)\">Attention \u2014 surveiller la capacit\u00e9 de remboursement</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&gt; 3</td><td style=\"padding:10px 20px;color:var(--ink2)\">Risqu\u00e9 \u2014 sauf banques, utilities et REIT (D/E \u00e9lev\u00e9 structurel)</td></tr>\n</table>\n</div>\n<div style=\"background:var(--surface2);border-left:4px solid var(--amber);border-radius:0 8px 8px 0;padding:16px 22px;margin:20px 0\">\n<p style=\"font-size:0.88rem;line-height:1.65;color:var(--ink2);margin:0\"><strong>Nuance sectorielle :</strong> Un D/E \u00e9lev\u00e9 chez une entreprise tech est un signal d'alarme. Le m\u00eame D/E chez une banque est parfaitement normal \u2014 leur mod\u00e8le consiste \u00e0 emprunter pour pr\u00eater. Comparez toujours dans le m\u00eame secteur.</p>\n</div>",
  20: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Sant\u00e9 financi\u00e8re</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">La Dette / EBITDA \u2014 Combien d'ann\u00e9es pour rembourser ?</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 5 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le ratio D/E vous dit <em>combien</em> une entreprise a de dettes. Mais il ne r\u00e9pond pas \u00e0 la vraie question des cr\u00e9anciers : <strong>en combien d'ann\u00e9es l'entreprise pourrait-elle rembourser en consacrant tous ses profits op\u00e9rationnels ?</strong> C'est exactement ce que mesure la <strong>Dette Nette / EBITDA</strong>.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">Dette Nette / EBITDA</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Dette nette = Dettes financi\u00e8res totales \u2212 Tr\u00e9sorerie \u00b7 EBITDA = B\u00e9n\u00e9fice avant int\u00e9r\u00eats, imp\u00f4ts, d\u00e9pr\u00e9ciations et amortissements</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La jauge de levier</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"background:var(--surface2);border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Ratio</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Zone</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">0 \u2013 2\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">Confortable \u2014 les banques pr\u00eatent facilement</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">2 \u2013 3\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">Vigilance \u2014 standard acceptable, surveiller l'\u00e9volution</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">3 \u2013 4\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">Tendu \u2014 refinancement difficile, seuil bancaire d\u00e9pass\u00e9</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&gt; 4\u00d7</td><td style=\"padding:10px 20px;color:var(--ink2)\">Zone de danger \u2014 risque de restructuration</td></tr>\n</table>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">Les banques int\u00e8grent souvent un <em>covenant</em> exigeant que ce ratio reste sous 3\u00d7. Au-del\u00e0, le pr\u00eat peut \u00eatre d\u00e9clar\u00e9 exigible ou le taux r\u00e9vis\u00e9 \u00e0 la hausse. Ce seuil est donc une information pr\u00e9cieuse sur la libert\u00e9 de man\u0153uvre financi\u00e8re d'une entreprise.</p>",
  21: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Sant\u00e9 financi\u00e8re</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Ratio de Couverture des Int\u00e9r\u00eats \u2014 L'entreprise peut-elle payer ses int\u00e9r\u00eats ?</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 4 min \u00b7 Niveau : D\u00e9butant</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Avoir des dettes, c'est accepter de payer des int\u00e9r\u00eats. Si les profits op\u00e9rationnels ne suffisent m\u00eame plus \u00e0 les couvrir, l'entreprise doit puiser dans sa tr\u00e9sorerie \u2014 ou pire, emprunter pour payer ses cr\u00e9anciers. Le <strong>Ratio de Couverture des Int\u00e9r\u00eats (ICR)</strong> mesure pr\u00e9cis\u00e9ment cette capacit\u00e9.</p>\n<div style=\"background:var(--surface2);border-left:4px solid var(--rose);border-radius:0 8px 8px 0;padding:20px 28px;margin:20px 0;text-align:center\">\n<div style=\"font-family:Georgia,serif;font-size:1.4rem;color:var(--ink)\">ICR = EBIT / Charges d'int\u00e9r\u00eats</div>\n<div style=\"font-size:0.72rem;color:var(--muted);margin-top:12px\">Un ICR de 5 signifie que les profits op\u00e9rationnels sont 5 fois sup\u00e9rieurs aux int\u00e9r\u00eats \u00e0 payer</div>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin:24px 0\">\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"background:var(--surface2);border-bottom:1px solid var(--border)\"><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">ICR</th><th style=\"padding:10px 20px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Signification</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">&lt; 1</td><td style=\"padding:10px 20px;color:var(--ink2)\">D\u00e9ficit \u2014 les profits ne couvrent pas les int\u00e9r\u00eats</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--rose);font-weight:700\">1 \u2013 2</td><td style=\"padding:10px 20px;color:var(--ink2)\">Fragile \u2014 toute baisse des profits cr\u00e9e un d\u00e9ficit</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 20px;color:var(--amber);font-weight:700\">2 \u2013 5</td><td style=\"padding:10px 20px;color:var(--ink2)\">Correct \u2014 marge de s\u00e9curit\u00e9 raisonnable</td></tr>\n<tr><td style=\"padding:10px 20px;color:var(--teal);font-weight:700\">&gt; 5</td><td style=\"padding:10px 20px;color:var(--ink2)\">Solide \u2014 large coussin, peut absorber un choc \u00e9conomique</td></tr>\n</table>\n</div>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2)\">L'ICR est le compl\u00e9ment indispensable du D/E. Deux entreprises avec le m\u00eame D/E mais des taux d'int\u00e9r\u00eat tr\u00e8s diff\u00e9rents (2 % vs 8 %) auront des ICR radicalement oppos\u00e9s. En p\u00e9riode de hausse des taux, l'ICR devient critique.</p>",
  22: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le DCF \u2014 Pourquoi 100 \u20ac demain valent moins que 100 \u20ac aujourd'hui</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 7 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le <strong>Discounted Cash Flow (DCF)</strong> est la m\u00e9thode de valorisation fondamentale par excellence. Son principe : une entreprise vaut la somme de tous les flux de tr\u00e9sorerie qu'elle va g\u00e9n\u00e9rer dans le futur, ramen\u00e9s \u00e0 leur valeur d'aujourd'hui.</p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">L'intuition : la valeur temps de l'argent</h2>\n<div style=\"background:var(--surface2);border-left:3px solid var(--blue);border-radius:0 6px 6px 0;padding:16px 20px;margin-bottom:20px;font-size:0.88rem;line-height:1.65;color:var(--ink2)\">\n<strong>Trois raisons pour lesquelles 100 \u20ac dans 10 ans valent moins qu'aujourd'hui :</strong><br>\n<span style=\"display:block;margin-top:8px\">\u2460 <strong>L'inflation</strong> \u2014 100 \u20ac ach\u00e8teront moins de biens dans 10 ans.</span>\n<span style=\"display:block;margin-top:4px\">\u2461 <strong>Le risque</strong> \u2014 L'entreprise pourrait ne pas tenir ses promesses.</span>\n<span style=\"display:block;margin-top:4px\">\u2462 <strong>Le co\u00fbt d'opportunit\u00e9</strong> \u2014 100 \u20ac aujourd'hui peuvent \u00eatre investis et cro\u00eetre.</span>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:20px 24px;margin-bottom:24px;text-align:center\">\n<p style=\"font-family:var(--font-serif);font-size:1.05rem;color:var(--ink);margin:0 0 10px\">Valeur = \u03a3 FCF<sub>t</sub> / (1 + r)<sup>t</sup> + Valeur Terminale / (1 + r)<sup>n</sup></p>\n<p style=\"font-size:0.78rem;color:var(--muted);margin:0\">FCF<sub>t</sub> = Free Cash Flow \u00e0 l'ann\u00e9e t \u00b7 r = taux d'actualisation (WACC) \u00b7 n = dur\u00e9e de pr\u00e9vision</p>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les 3 param\u00e8tres qui font tout</h2>\n<div style=\"display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-bottom:28px\">\n<div style=\"background:var(--surface);border:1px solid var(--border);border-top:3px solid var(--blue);border-radius:6px;padding:14px 16px\">\n<div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--blue);margin-bottom:8px\">FCF pr\u00e9visionnel</div>\n<p style=\"font-size:0.83rem;line-height:1.6;color:var(--ink2);margin:0\">Les flux de tr\u00e9sorerie libres attendus chaque ann\u00e9e, bas\u00e9s sur les revenus et marges futurs.</p>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-top:3px solid var(--teal);border-radius:6px;padding:14px 16px\">\n<div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--teal);margin-bottom:8px\">Taux d'actualisation</div>\n<p style=\"font-size:0.83rem;line-height:1.6;color:var(--ink2);margin:0\">Le WACC refl\u00e8te le risque per\u00e7u de l'entreprise et le co\u00fbt de ses financements.</p>\n</div>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-top:3px solid var(--amber);border-radius:6px;padding:14px 16px\">\n<div style=\"font-size:0.68rem;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:var(--amber);margin-bottom:8px\">Valeur terminale</div>\n<p style=\"font-size:0.83rem;line-height:1.6;color:var(--ink2);margin:0\">La valeur au-del\u00e0 de la p\u00e9riode de pr\u00e9vision \u2014 repr\u00e9sente souvent 60\u201380 % de la valeur totale.</p>\n</div>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">La sensibilit\u00e9 : le talon d'Achille du DCF</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:8px;overflow:hidden;margin-bottom:24px\">\n<div style=\"background:var(--surface2);padding:10px 16px;border-bottom:1px solid var(--border)\"><span style=\"font-size:0.72rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Impact du WACC \u2014 FCF de 100 M\u20ac/an sur 10 ans</span></div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 16px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">WACC</th><th style=\"padding:10px 16px;text-align:right;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Valeur calcul\u00e9e</th><th style=\"padding:10px 16px;text-align:right;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">\u00c9cart vs 8 %</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--ink2)\">6 %</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:600;color:var(--teal)\">1 472 M\u20ac</td><td style=\"padding:10px 16px;text-align:right;color:var(--teal)\">+27 %</td></tr>\n<tr style=\"border-bottom:1px solid var(--border);background:var(--surface2)\"><td style=\"padding:10px 16px;color:var(--ink);font-weight:600\">8 % (base)</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:700\">1 158 M\u20ac</td><td style=\"padding:10px 16px;text-align:right;color:var(--muted)\">\u2014</td></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--ink2)\">10 %</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:600;color:var(--rose)\">886 M\u20ac</td><td style=\"padding:10px 16px;text-align:right;color:var(--rose)\">\u221223 %</td></tr>\n<tr><td style=\"padding:10px 16px;color:var(--ink2)\">12 %</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:600;color:var(--rose)\">694 M\u20ac</td><td style=\"padding:10px 16px;text-align:right;color:var(--rose)\">\u221240 %</td></tr>\n</table>\n</div>\n<div style=\"background:var(--surface2);border-left:3px solid var(--amber);border-radius:0 6px 6px 0;padding:16px 20px;font-size:0.88rem;line-height:1.65;color:var(--ink2)\"><strong style=\"color:var(--amber)\">\u00c0 retenir :</strong> Une variation de seulement 2 points de WACC peut faire bouger la valorisation de 20 \u00e0 30 %. Le DCF n'est pas une v\u00e9rit\u00e9 \u2014 c'est une <strong>fourchette raisonn\u00e9e</strong>. La rigueur est dans les hypoth\u00e8ses, pas dans la pr\u00e9cision des chiffres.</div>",
  23: "<div style=\"font-size:0.62rem;font-weight:700;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-bottom:12px\">Finance \u00b7 Valorisation</div>\n<h1 style=\"font-family:var(--font-serif);font-size:2rem;font-weight:700;line-height:1.25;color:var(--ink);margin-bottom:10px\">Le Reverse DCF \u2014 Quelle croissance le march\u00e9 parie-t-il sur ce titre ?</h1>\n<p style=\"font-size:0.8rem;color:var(--muted);margin-bottom:32px\">Lecture : 6 min \u00b7 Niveau : Interm\u00e9diaire</p>\n<p style=\"font-size:1rem;line-height:1.75;color:var(--ink2);margin-bottom:20px\">Le DCF classique part d'hypoth\u00e8ses pour arriver \u00e0 une valeur. Le <strong>Reverse DCF</strong> fait exactement l'inverse : il part du prix actuel de march\u00e9 pour remonter aux hypoth\u00e8ses de croissance que ce prix implique. Une seule question : <em>est-ce que ces hypoth\u00e8ses sont r\u00e9alistes ?</em></p>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Le vrai avantage : \u00e9viter de se convaincre soi-m\u00eame</h2>\n<div style=\"background:var(--surface2);border-left:3px solid var(--teal);border-radius:0 6px 6px 0;padding:16px 20px;margin-bottom:20px;font-size:0.88rem;line-height:1.65;color:var(--ink2)\">\n<strong style=\"color:var(--teal)\">Le biais classique du DCF :</strong> on choisit inconsciemment des hypoth\u00e8ses qui confirment une conviction pr\u00e9existante. On veut acheter \u2192 on projette 20 % de croissance \u2192 le DCF dit \"sous-\u00e9valu\u00e9\". Le Reverse DCF coupe court \u00e0 ce biais en testant les hypoth\u00e8ses du march\u00e9, pas les siennes.\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Exemple concret</h2>\n<div style=\"background:var(--surface);border:1px solid var(--border);border-radius:8px;overflow:hidden;margin-bottom:24px\">\n<div style=\"background:var(--surface2);padding:10px 16px;border-bottom:1px solid var(--border)\"><span style=\"font-size:0.72rem;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)\">Analyse Reverse DCF \u2014 WACC 9 %</span></div>\n<table style=\"width:100%;border-collapse:collapse;font-size:0.85rem\">\n<tr style=\"border-bottom:1px solid var(--border)\"><th style=\"padding:10px 16px;text-align:left;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Sc\u00e9nario</th><th style=\"padding:10px 16px;text-align:right;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Croissance implicite FCF</th><th style=\"padding:10px 16px;text-align:right;color:var(--muted);font-size:0.68rem;font-weight:600;text-transform:uppercase\">Jugement</th></tr>\n<tr style=\"border-bottom:1px solid var(--border)\"><td style=\"padding:10px 16px;color:var(--ink2)\">Cours actuel \u00e9lev\u00e9</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:700;color:var(--rose)\">+24 % / an</td><td style=\"padding:10px 16px;text-align:right;color:var(--rose);font-weight:600\">Exigeant</td></tr>\n<tr style=\"border-bottom:1px solid var(--border);background:var(--surface2)\"><td style=\"padding:10px 16px;color:var(--ink2)\">Cours neutre</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:700;color:var(--amber)\">+15 % / an</td><td style=\"padding:10px 16px;text-align:right;color:var(--amber);font-weight:600\">Raisonnable</td></tr>\n<tr><td style=\"padding:10px 16px;color:var(--ink2)\">Cours d\u00e9cot\u00e9</td><td style=\"padding:10px 16px;text-align:right;font-family:var(--font-serif);font-weight:700;color:var(--teal)\">+9 % / an</td><td style=\"padding:10px 16px;text-align:right;color:var(--teal);font-weight:600\">Conservateur</td></tr>\n</table>\n</div>\n<h2 style=\"font-family:var(--font-serif);font-size:1.25rem;font-weight:700;color:var(--ink);margin:28px 0 12px\">Les trois conclusions possibles</h2>\n<div style=\"display:flex;flex-direction:column;gap:10px;margin-bottom:28px\">\n<div style=\"display:flex;align-items:flex-start;gap:12px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:12px 16px\">\n<div style=\"width:8px;height:8px;border-radius:50%;background:var(--teal);flex-shrink:0;margin-top:5px\"></div>\n<p style=\"font-size:0.88rem;line-height:1.6;color:var(--ink2);margin:0\"><strong style=\"color:var(--teal)\">Hypoth\u00e8ses conservatrices</strong> \u2014 le march\u00e9 sous-estime la croissance probable \u2192 signal d'opportunit\u00e9 potentielle.</p>\n</div>\n<div style=\"display:flex;align-items:flex-start;gap:12px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:12px 16px\">\n<div style=\"width:8px;height:8px;border-radius:50%;background:var(--amber);flex-shrink:0;margin-top:5px\"></div>\n<p style=\"font-size:0.88rem;line-height:1.6;color:var(--ink2);margin:0\"><strong style=\"color:var(--amber)\">Hypoth\u00e8ses raisonnables</strong> \u2014 le prix refl\u00e8te correctement les fondamentaux.</p>\n</div>\n<div style=\"display:flex;align-items:flex-start;gap:12px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:12px 16px\">\n<div style=\"width:8px;height:8px;border-radius:50%;background:var(--rose);flex-shrink:0;margin-top:5px\"></div>\n<p style=\"font-size:0.88rem;line-height:1.6;color:var(--ink2);margin:0\"><strong style=\"color:var(--rose)\">Hypoth\u00e8ses irr\u00e9alistes</strong> \u2014 le prix int\u00e8gre une perfection improbable \u2192 risque de d\u00e9ception et re-rating.</p>\n</div>\n</div>\n<div style=\"background:var(--surface2);border-left:3px solid var(--amber);border-radius:0 6px 6px 0;padding:16px 20px;font-size:0.88rem;line-height:1.65;color:var(--ink2)\"><strong style=\"color:var(--amber)\">En r\u00e9sum\u00e9 :</strong> Le Reverse DCF discipline l'analyse. Il force l'investisseur \u00e0 confronter son optimisme \u00e0 la r\u00e9alit\u00e9 math\u00e9matique du prix, et \u00e0 formuler clairement pourquoi il pense que le march\u00e9 a tort \u2014 ou raison.</div>",
});

